// Process All Users - filter to users with 50+ unanalysed emails
const supabaseUrl = 'https://rmcyfrqgmpnkvrgzeyxq.supabase.co';
const supabaseKey = 'YOUR_SUPABASE_SERVICE_ROLE_KEY';

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const users = $input.all();
const qualifying = [];

for (const userItem of users) {
  const user = userItem.json;

  // Count unanalysed emails for this user via Supabase REST API
  const emailIds = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/email_events?user_id=eq.${user.id}&analysed=eq.false&select=id`,
    headers
  });

  const emailCount = Array.isArray(emailIds) ? emailIds.length : 0;

  if (emailCount >= 50) {
    qualifying.push({
      id: user.id,
      email: user.email,
      first_name: user.first_name,
      plan: user.plan,
      industry: user.industry,
      email_count: emailCount
    });
  }
}

return [{
  json: {
    qualifying_users: qualifying,
    qualifying_count: qualifying.length
  }
}];

// Split qualifying users array into individual items for per-user processing
const data = $input.first().json;
const users = data.qualifying_users || [];

if (users.length === 0) {
  return [{ json: { empty: true } }];
}

return users.map(user => ({ json: user }));

// Collect full performance data for each qualifying user
const supabaseUrl = 'https://rmcyfrqgmpnkvrgzeyxq.supabase.co';
const supabaseKey = 'YOUR_SUPABASE_SERVICE_ROLE_KEY';

const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const items = $input.all();
const results = [];

for (const item of items) {
  const userId = item.json.id;
  const userInfo = item.json;

  // Query A: Campaign metrics via RPC
  let campaignMetrics = [];
  try {
    campaignMetrics = await this.helpers.httpRequest({
      method: 'POST',
      url: `${supabaseUrl}/rest/v1/rpc/get_campaign_metrics`,
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_user_id: userId })
    });
  } catch (e) {
    // RPC function may not exist yet - continue with empty metrics
  }

  // Query B: Email events
  const events = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/email_events?user_id=eq.${userId}&analysed=eq.false&select=event_type,occurred_at,campaign_id,step_index,metadata`,
    headers
  });

  // Aggregate event types
  const eventCounts = events.reduce((acc, e) => {
    acc[e.event_type] = (acc[e.event_type] || 0) + 1;
    return acc;
  }, {});

  const totalSent = eventCounts['sent'] || 0;
  const openRate = totalSent > 0 ? ((eventCounts['opened'] || 0) / totalSent * 100).toFixed(2) : 0;
  const clickRate = totalSent > 0 ? ((eventCounts['clicked'] || 0) / totalSent * 100).toFixed(2) : 0;
  const replyRate = totalSent > 0 ? ((eventCounts['replied'] || 0) / totalSent * 100).toFixed(2) : 0;
  const bounceRate = totalSent > 0 ? ((eventCounts['bounced'] || 0) / totalSent * 100).toFixed(2) : 0;

  // Query C: Sequence step performance
  let stepPerf = [];
  try {
    stepPerf = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/rest/v1/sequence_step_logs?user_id=eq.${userId}&select=step_index,event_type,ab_variant`,
      headers
    });
  } catch (e) {
    // Table may not exist yet
  }

  // Query D: Intent accuracy (limit 100 leads)
  const leads = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/leads?user_id=eq.${userId}&select=intent_score,id&limit=100`,
    headers
  });

  const periodStart = events.length > 0
    ? events.reduce((min, e) => e.occurred_at < min ? e.occurred_at : min, events[0].occurred_at)
    : new Date().toISOString();

  const periodEnd = new Date().toISOString();

  results.push({
    json: {
      user_id: userId,
      user_email: userInfo.email,
      user_first_name: userInfo.first_name || 'there',
      user_industry: userInfo.industry || 'general',
      email_count: events.length,
      period_start: periodStart,
      period_end: periodEnd,
      performance_data: {
        total_sent: totalSent,
        open_rate: parseFloat(openRate),
        click_rate: parseFloat(clickRate),
        reply_rate: parseFloat(replyRate),
        bounce_rate: parseFloat(bounceRate),
        event_breakdown: eventCounts,
        campaign_metrics: campaignMetrics,
        step_performance: stepPerf,
        intent_data: leads
      }
    }
  });
}

return results;

const claudeText = $input.first().json.content[0].text;
const cleaned = claudeText.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
const parsed = JSON.parse(cleaned);
return [{
  json: {
    ...$input.first().json,
    clean_report: parsed,
    clean_report_string: JSON.stringify(parsed)
  }
}];

