const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{ json: { skipped: true, reason: 'No users processed this cycle' } }];
}

const totalUsers = allItems.length;
const totalEmails = allItems.reduce((sum, item) => sum + (item.json.email_count || 0), 0);

const avgOpenRate = allItems.reduce((sum, item) => sum + (item.json.performance_data?.open_rate || 0), 0) / totalUsers;
const avgClickRate = allItems.reduce((sum, item) => sum + (item.json.performance_data?.click_rate || 0), 0) / totalUsers;
const avgReplyRate = allItems.reduce((sum, item) => sum + (item.json.performance_data?.reply_rate || 0), 0) / totalUsers;
const avgBounceRate = allItems.reduce((sum, item) => sum + (item.json.performance_data?.bounce_rate || 0), 0) / totalUsers;

return [{
  json: {
    total_users: totalUsers,
    total_emails: totalEmails,
    avg_open_rate: parseFloat(avgOpenRate.toFixed(2)),
    avg_click_rate: parseFloat(avgClickRate.toFixed(2)),
    avg_reply_rate: parseFloat(avgReplyRate.toFixed(2)),
    avg_bounce_rate: parseFloat(avgBounceRate.toFixed(2)),
    top_subject_patterns: [],
    worst_subject_patterns: [],
    intent_accuracy: 0,
    spam_false_positive_rate: 0,
    spam_false_negative_rate: 0,
    recommendations: []
  }
}];
